 578→   578→        for (i, constraint_opt) in sym_constraints.iter().enumerate() {
 579→   579→            if constraint_opt.is_none() && i < obs.result.branch_path.len() {
 580→   580→                let bd = &obs.result.branch_path[i];
 581→   581→                let opposite_seen =
 582→   582→                    seen_branch_sides.contains(&(bd.branch_id, !bd.taken));
 583→   583→
 584→   584→                if opposite_seen
 585→   585→                    && let Some((tw, fw)) =
 586→   586→                        boundary_search::find_witness_pair(raw_results, bd.branch_id)
 587→   587→                {
 588→   588→                    let candidates = boundary_search::interpolate_inputs(
 589→   589→                        &tw,
 590→   590→                        &fw,
 591→   591→                        param_infos,
 592→   592→                        boundary_search::MAX_BOUNDARY_STEPS,
 593→   593→                    );
 594→   594→                    for interp in candidates {
 595→   595→                        output.candidates.push(WorklistEntry {
 596→   596→                            inputs: interp,
 597→   597→                            source: InputSource::BoundarySearch,
 598→   598→                            fitness: None,
 599→   599→                        });
 600→   600→                        output.boundary_count += 1;
 601→   601→                    }
 602→   602→                    boundary_attempted = true;
 603→   603→                    boundary_branches += 1;
 604→   604→                    if boundary_branches
 605→   605→                        >= boundary_search::MAX_BOUNDARY_BRANCHES_PER_ROUND
 606→   606→                    {
 607→   607→                        break;
 608→   608→                    }
 609→   609→                }
 610→   610→            }
 611→   611→        }
 612→   612→
 613→   613→        // Fall back to type-aware mutation if boundary search wasn't applicable.
 614→   614→        //
 615→   615→        // Uses input_gen::mutate_inputs (type-aware, respects param types) for
 616→   616→        // several rounds, plus the legacy fuzz_inputs as a cheap supplement.
 617→   617→        if !boundary_attempted {
 618→   618→            for (i, constraint_opt) in sym_constraints.iter().enumerate() {
 619→   619→                if constraint_opt.is_none() && i < obs.result.branch_path.len() {
 620→   620→                    // Type-aware mutations (3 rounds at full mutation rate).
 621→   621→                    for _ in 0..MUTATE_ROUNDS_PER_UNKNOWN {
 622→   622→                        let mutated = input_gen::mutate_inputs(
 623→   623→                            &obs.inputs,
 624→   624→                            param_infos,
 625→   625→                            MUTATE_RATE_UNKNOWN,
 626→   626→                            &[],
 627→   627→                            rng,
 628→   628→                        );
 629→   629→                        output.candidates.push(WorklistEntry {
 630→   630→                            inputs: mutated,
 631→   631→                            source: InputSource::Fuzzed,
 632→   632→                            fitness: None,
 633→   633→                        });
 634→   634→                        output.fuzz_count += 1;
 635→   635→                    }
 636→   636→                    // Legacy deterministic fuzz as supplement.
 637→   637→                    for fuzzed in fuzz_inputs(&obs.inputs) {
 638→   638→                        output.candidates.push(WorklistEntry {
 639→   639→                            inputs: fuzzed,
 640→   640→                            source: InputSource::Fuzzed,
 641→   641→                            fitness: None,
 642→   642→                        });
 643→   643→                        output.fuzz_count += 1;
 644→   644→                    }
 645→   645→                    // Only fuzz once per observation (avoid exponential blowup).
 646→   646→                    break;
 647→   647→                }
 648→   648→            }
 649→   649→        }
 650→   650→    }
 651→   651→
 652→   652→    // Parameter drilling: for stalled frontiers, generate targeted mutations.
 653→   653→    {
 654→   654→        let mut stalled: Vec<Frontier> = frontier_set
 655→   655→            .iter()
 656→   656→            .filter(|f| {
 657→   657→                f.stall_count >= drilling::DRILL_STALL_THRESHOLD
 658→   658→                    && f.stall_count < crate::frontier::DEFAULT_MAX_STALL
 659→   659→            })
 660→   660→            .cloned()
 661→   661→            .collect();
 662→   662→        stalled.sort_by(|a, b| a.depth.cmp(&b.depth).then(a.stall_count.cmp(&b.stall_count)));
 663→   663→        stalled.truncate(drilling::MAX_FRONTIERS_PER_ROUND);
 664→   664→
 665→   665→        for frontier in &stalled {
 666→   666→            let count =
 667→   667→                drilling::DRILL_MUTATIONS_PER_PARAM * frontier.blocking_params.len().max(1);
 668→   668→            let drilled = drilling::generate_drilled_inputs(
 669→   669→                &frontier.best_prefix,
 670→   670→                &frontier.blocking_params,
 671→   671→                param_infos,
 672→   672→                count,
 673→   673→                rng,
 674→   674→            );
 675→   675→            for inputs in drilled {
 676→   676→                output.candidates.push(WorklistEntry {
 677→   677→                    inputs,
 678→   678→                    source: InputSource::Drilled,
 679→   679→                    fitness: None,
 680→   680→                });
 681→   681→                output.drill_count += 1;
 682→   682→            }
 683→   683→            frontier_set.increment_stall(frontier.branch_id);
 684→   684→        }
 685→   685→    }
 686→   686→
 687→   687→    // Score each candidate using genetic fitness. The parent observation's
 688→   688→    // branch path gives us approximate fitness context: candidates derived
 689→   689→    // from high-fitness executions should be explored first.
 690→   690→    if !target_branches.is_empty() {
 691→   691→        for candidate in &mut output.candidates {
 692→   692→            // Create a synthetic ExecuteResult from the parent observation's
 693→   693→            // branch path to estimate fitness. This gives candidates a
 694→   694→            // relative ranking even before execution.
 695→   695→            if let Some(parent_obs) = observations.iter().find(|o| o.is_new_path) {
 696→   696→                let breakdown = crate::genetic_fitness::score(
 697→   697→                    &parent_obs.result,
 698→   698→                    target_branches,
 699→   699→                    fitness_context,
 700→   700→                    fitness_weights,
 701→   701→                );
 702→   702→                candidate.fitness = Some(breakdown.total);
 703→   703→            }
 704→   704→        }
 705→   705→    }
 706→   706→
 707→   707→    output
 708→   708→}
 709→   709→
 710→   710→/// Run the concolic exploration loop on a function via a frontend subprocess.
 711→   711→///
 712→   712→/// The loop alternates between two phases per round:
 713→   713→/// 1. **Observe** — drain the worklist, execute all inputs, classify paths
 714→   714→/// 2. **Solve/Generate** — extract constraints from new paths, produce candidates
 715→   715→///
 716→   716→/// `function_name` is the fully-qualified name of the function to explore.
 717→   717→/// `seed_inputs` provides initial input sets to begin exploration.
 718→   718→/// `user_inputs` provides user-provided candidate inputs (highest priority).
 719→   719→/// `param_infos` provides parameter metadata including names and types.
 720→   720→pub async fn explore(
 721→   721→    frontend: &mut Frontend,
 722→   722→    function_name: &str,
 723→   723→    seed_inputs: Vec<Vec<serde_json::Value>>,
 724→   724→    user_inputs: Vec<Vec<serde_json::Value>>,
 725→   725→    param_infos: &[ParamInfo],
 726→   726→    config: &ExploreConfig,
 727→   727→) -> Result<ExploreResult, ExploreError> {
 728→   728→    let param_names: Vec<String> = param_infos.iter().map(|p| p.name.clone()).collect();
 729→   729→    let mut worklist = BinaryHeap::new();
 730→   730→    let mut covered_paths: HashSet<u64> = HashSet::new();
 731→   731→    let mut executions = Vec::new();
 732→   732→    let mut raw_results: Vec<(Vec<serde_json::Value>, ExecuteResult)> = Vec::new();
 733→   733→    let mut seen_branch_ids: HashSet<u32> = HashSet::new();
 734→   734→    let mut discoveries: Vec<(u32, DiscoveryMethod)> = Vec::new();
 735→   735→    let mut total_executions: usize = 0;
 736→   736→    let mut z3_generated: usize = 0;
 737→   737→    let mut fuzz_generated: usize = 0;
 738→   738→    let mut boundary_generated: usize = 0;
 739→   739→    let mut drill_generated: usize = 0;
 740→   740→    let mut termination_reason = TerminationReason::WorklistExhausted;
 741→   741→    let mut seen_branch_sides: HashSet<(u32, bool)> = HashSet::new();
 742→   742→    let mut frontier_set = FrontierSet::new();
 743→   743→    let mut rng = StdRng::from_os_rng();
 744→   744→    let mut triage_state = TriageState::new(param_names.clone());
 745→   745→    let mut triage_skipped: usize = 0;
 746→   746→    let mut triage_mispredictions: usize = 0;
 747→   747→
 748→   748→    // Fitness context shares novelty state with covered_paths — the
 749→   749→    // orchestrator marks paths as seen in both sets whenever a new path
 750→   750→    // is discovered, keeping FitnessContext's novelty scoring in sync.
 751→   751→    let mut fitness_context = FitnessContext::new();
 752→   752→    let fitness_weights = FitnessWeights::default();
 753→   753→
 754→   754→    // Target branches: branch IDs seen so far on only one side (not yet
 755→   755→    // covered on the opposite). Updated after each new-path observation.
 756→   756→    // Used by fitness scoring to compute proximity/coverage scores.
 757→   757→    let mut target_branches: HashSet<u32> = HashSet::new();
 758→   758→
 759→   759→    // MetaStrategy integration point: strategies will be registered here
 760→   760→    // by a follow-up issue that replaces the hardcoded seed/fuzz/drill
 761→   761→    // generation with adaptive strategy selection.
 762→   762→    let _meta_strategy: MetaStrategy = MetaStrategy::new(vec![], Default::default());
 763→   763→
 764→   764→    // Add user-provided candidates with highest priority.
 765→   765→    for inputs in user_inputs {
 766→   766→        worklist.push(WorklistEntry {
 767→   767→            inputs,
 768→   768→            source: InputSource::UserProvided,
 769→   769→            fitness: None,
 770→   770→        });
 771→   771→    }
 772→   772→
 773→   773→    // Seed the worklist.
 774→   774→    for inputs in seed_inputs {
 775→   775→        worklist.push(WorklistEntry {
 776→   776→            inputs,
 777→   777→            source: InputSource::Seed,
 778→   778→            fitness: None,
 779→   779→        });
 780→   780→    }
 781→   781→
 782→   782→    // --- Float probe phase ---
 783→   783→    let float_indices = crate::float_probe::float_param_indices(param_infos);
 784→   784→    let mut float_probe_results: Vec<crate::float_probe::FloatProbeResult> = Vec::new();
 785→   785→    if !float_indices.is_empty() {
 786→   786→        for &idx in &float_indices {
 787→   787→            let pairs = crate::float_probe::generate_probe_pairs(
 788→   788→                param_infos,
 789→   789→                idx,
 790→   790→                crate::float_probe::PROBE_COUNT,
 791→   791→                &mut rng,
 792→   792→            );
 793→   793→            let mut agreements = 0usize;
 794→   794→            let mut total_probes = 0usize;
 795→   795→            let mut divergent_values = Vec::new();
 796→   796→
 797→   797→            for (float_inputs, floor_inputs) in pairs {
 798→   798→                let float_resp = frontend
 799→   799→                    .send(Command::Execute {
 800→   800→                        function: function_name.to_string(),
 801→   801→                        inputs: float_inputs.clone(),
 802→   802→                        mocks: config.mocks.clone(),
 803→   803→                        setup_context: None,
 804→   804→                    })
 805→   805→                    .await?;
 806→   806→
 807→   807→                let floor_resp = frontend
 808→   808→                    .send(Command::Execute {
 809→   809→                        function: function_name.to_string(),
 810→   810→                        inputs: floor_inputs,
 811→   811→                        mocks: config.mocks.clone(),
 812→   812→                        setup_context: None,
 813→   813→                    })
 814→   814→                    .await?;
 815→   815→
 816→   816→                if let (
 817→   817→                    ResponseResult::Execute(float_result),
 818→   818→                    ResponseResult::Execute(floor_result),
 819→   819→                ) = (&float_resp.result, &floor_resp.result)
 820→   820→                {
 821→   821→                    total_probes += 1;
 822→   822→
 823→   823→                    if crate::float_probe::executions_agree(float_result, floor_result) {
 824→   824→                        agreements += 1;
 825→   825→                    } else if let Some(v) = float_inputs.get(idx).and_then(|v| v.as_f64()) {
 826→   826→                        divergent_values.push(v);
 827→   827→                    }
 828→   828→                }
 829→   829→            }
 830→   830→
 831→   831→            let classification = crate::float_probe::classify(
 832→   832→                agreements,
 833→   833→                total_probes,
 834→   834→                crate::float_probe::AGREEMENT_THRESHOLD,
 835→   835→            );
 836→   836→            float_probe_results.push(crate::float_probe::FloatProbeResult {
 837→   837→                param_index: idx,
 838→   838→                param_name: param_infos[idx].name.clone(),
 839→   839→                classification,
 840→   840→                agreements,
 841→   841→                total_probes,
 842→   842→                divergent_values,
 843→   843→            });
 844→   844→        }
 845→   845→    }
 846→   846→
 847→   847→    let explore_start = Instant::now();
 848→   848→    let mut plateau_counter: usize = 0;
 849→   849→
 850→   850→    // --- Two-phase exploration loop: Observe → Solve/Generate ---
 851→   851→    //
 852→   852→    // Each iteration processes one worklist entry:
 853→   853→    //   1. Observe — execute the entry, classify the path
 854→   854→    //   2. Solve/Generate — if new path, extract constraints and produce candidates
 855→   855→    //
 856→   856→    // Solving after each observation (not batched) preserves the original
 857→   857→    // convergence behavior: Z3 candidates from observation N are available
 858→   858→    // for execution at iteration N+1.
 859→   859→    while let Some(entry) = worklist.pop() {
 860→   860→        // Phase 1: Observe — execute and classify one worklist entry.
 861→   861→        let budget = ExploreBudget {
 862→   862→            unique_paths: executions.len(),
 863→   863→            total_executions,
 864→   864→            plateau_counter,
 865→   865→            explore_start,
 866→   866→        };
 867→   867→
 868→   868→        let observe_result = observe_one(
 869→   869→            &entry,
 870→   870→            frontend,
 871→   871→            function_name,
 872→   872→            config,
 873→   873→            &mut covered_paths,
 874→   874→            &mut triage_state,
 875→   875→            &budget,
 876→   876→        )
 877→   877→        .await?;
 878→   878→
 879→   879→        let obs = match observe_result {
 880→   880→            ObserveOneResult::Observed(obs) => *obs,
 881→   881→            ObserveOneResult::TriageSkipped => {
 882→   882→                triage_skipped += 1;
 883→   883→                continue;
 884→   884→            }
 885→   885→            ObserveOneResult::FrontendSkipped => {
 886→   886→                total_executions += 1;
 887→   887→                continue;
 888→   888→            }
 889→   889→            ObserveOneResult::Terminated(reason) => {
 890→   890→                termination_reason = reason;
 891→   891→                break;
 892→   892→            }
 893→   893→        };
 894→   894→
 895→   895→        total_executions += 1;
 896→   896→        if obs.is_sampled_skip && !obs.is_new_path {
 897→   897→            // Prediction was correct (duplicate path) — no misprediction.
 898→   898→        } else if obs.is_sampled_skip && obs.is_new_path {
 899→   899→            triage_mispredictions += 1;
 900→   900→        }
 901→   901→
 902→   902→        // Record raw result for pipeline composability.
 903→   903→        raw_results.push((obs.inputs.clone(), obs.result.clone()));
 904→   904→
 905→   905→        if !obs.is_new_path {
 906→   906→            plateau_counter += 1;
 907→   907→            continue;
 908→   908→        }
 909→   909→
 910→   910→        // New path discovered — reset plateau counter.
 911→   911→        plateau_counter = 0;
 912→   912→
 913→   913→        // Track per-branch discovery attribution.
 914→   914→        let method = match obs.source {
 915→   915→            InputSource::Z3Solved => DiscoveryMethod::Z3,
 916→   916→            InputSource::UserProvided => DiscoveryMethod::UserProvided,
 917→   917→            InputSource::Drilled => DiscoveryMethod::Drilled,
 918→   918→            InputSource::BoundarySearch => DiscoveryMethod::BoundarySearch,
 919→   919→            InputSource::Seed | InputSource::Fuzzed => DiscoveryMethod::Random,
 920→   920→        };
 921→   921→        for decision in &obs.result.branch_path {
 922→   922→            if seen_branch_ids.insert(decision.branch_id) {
 923→   923→                discoveries.push((decision.branch_id, method));
 924→   924→            }
 925→   925→        }
 926→   926→
 927→   927→        // Update frontier set and target branches: track which branch sides
 928→   928→        // have been seen. Branches seen on only one side are targets for
 929→   929→        // fitness scoring.
 930→   930→        for decision in &obs.result.branch_path {
 931→   931→            seen_branch_sides.insert((decision.branch_id, decision.taken));
 932→   932→            let opposite_seen =
 933→   933→                seen_branch_sides.contains(&(decision.branch_id, !decision.taken));
 934→   934→            if opposite_seen {
 935→   935→                frontier_set.remove(decision.branch_id);
 936→   936→                target_branches.remove(&decision.branch_id);
 937→   937→            } else {
 938→   938→                target_branches.insert(decision.branch_id);
 939→   939→                let prev_stall = frontier_set
 940→   940→                    .iter()
 941→   941→                    .find(|f| f.branch_id == decision.branch_id)
 942→   942→                    .map_or(0, |f| f.stall_count);
 943→   943→                let blocking =
 944→   944→                    drilling::identify_blocking_params(&decision.constraint, param_infos);
 945→   945→                let depth =
 946→   946→                    drilling::branch_depth(&obs.result.branch_path, decision.branch_id);
 947→   947→                frontier_set.insert(Frontier {
 948→   948→                    branch_id: decision.branch_id,
 949→   949→                    depth,
 950→   950→                    blocking_params: blocking,
 951→   951→                    best_prefix: obs.inputs.clone(),
 952→   952→                    stall_count: prev_stall,
 953→   953→                });
 954→   954→            }
 955→   955→        }
 956→   956→
 957→   957→        // Sync fitness context: mark this path as seen so future fitness
 958→   958→        // scoring correctly identifies repeat paths as non-novel.
 959→   959→        fitness_context.mark_seen(obs.path_id);
 960→   960→
 961→   961→        executions.push(obs.result.clone());
 962→   962→
 963→   963→        // Phase 2: Solve/Generate — produce new candidates from this observation.
 964→   964→        let solve_output = solve_and_generate(
 965→   965→            &[obs],
 966→   966→            &mut frontier_set,
 967→   967→            param_infos,
 968→   968→            &param_names,
 969→   969→            &raw_results,
 970→   970→            &seen_branch_sides,
 971→   971→            config,
 972→   972→            &mut rng,
 973→   973→            &target_branches,
 974→   974→            &mut fitness_context,
 975→   975→            &fitness_weights,
 976→   976→        );
 977→   977→
 978→   978→        z3_generated += solve_output.z3_count;
 979→   979→        fuzz_generated += solve_output.fuzz_count;
 980→   980→        drill_generated += solve_output.drill_count;
 981→   981→        boundary_generated += solve_output.boundary_count;
 982→   982→
 983→   983→        for candidate in solve_output.candidates {
 984→   984→            worklist.push(candidate);
 985→   985→        }
 986→   986→    }
 987→   987→
 988→   988→    let unique_paths = covered_paths.len();
 989→   989→    Ok(ExploreResult {
 990→   990→        function_name: function_name.to_string(),
 991→   991→        total_lines: 0, // Caller must set from FunctionAnalysis (end_line - start_line + 1)
 992→   992→        executions,
 993→   993→        unique_paths,
 994→   994→        total_executions,
 995→   995→        z3_generated,
 996→   996→        fuzz_generated,
 997→   997→        boundary_generated,
 998→   998→        drill_generated,
 999→   999→        termination_reason,
1000→  1000→        raw_results,
1001→  1001→        discoveries,
1002→  1002→        triage_skipped,
1003→  1003→        triage_mispredictions,
1004→  1004→        nondeterministic_fields: vec![],
1005→  1005→        float_probe_results,
1006→  1006→    })
1007→  1007→}
1008→  1008→
1009→  1009→/// Simple input fuzzing: produce a handful of variations on the base inputs.
1010→  1010→///
1011→  1011→/// For each JSON value in the input list, generate mutations:
1012→  1012→/// - Numbers: ±1, ×-1, 0, boundary values
1013→  1013→/// - Booleans: flip
1014→  1014→/// - Strings: empty string, "a"
1015→  1015→pub(crate) fn fuzz_inputs(base: &[serde_json::Value]) -> Vec<Vec<serde_json::Value>> {
1016→  1016→    let mut results = Vec::new();
1017→  1017→
1018→  1018→    for (idx, val) in base.iter().enumerate() {
1019→  1019→        let mutations = fuzz_single_value(val);
1020→  1020→        for mutated in mutations {
1021→  1021→            let mut new_inputs = base.to_vec();
1022→  1022→            new_inputs[idx] = mutated;
1023→  1023→            results.push(new_inputs);
1024→  1024→        }
1025→  1025→    }
1026→  1026→
1027→  1027→    results
1028→  1028→}
1029→  1029→
1030→  1030→pub(crate) fn fuzz_single_value(val: &serde_json::Value) -> Vec<serde_json::Value> {
1031→  1031→    match val {
1032→  1032→        serde_json::Value::Number(n) => {
1033→  1033→            let mut mutations = Vec::new();
1034→  1034→            if let Some(i) = n.as_i64() {
1035→  1035→                let candidates = [i + 1, i - 1, 0, -i];
1036→  1036→                for c in candidates {
1037→  1037→                    let json_val = serde_json::json!(c);
1038→  1038→                    if c != i && !mutations.contains(&json_val) {
1039→  1039→                        mutations.push(json_val);
1040→  1040→                    }
1041→  1041→                }
1042→  1042→            } else if let Some(f) = n.as_f64() {
1043→  1043→                let candidates = [f + 1.0, f - 1.0, 0.0];
1044→  1044→                for c in candidates {
1045→  1045→                    let json_val = serde_json::json!(c);
1046→  1046→                    if (c - f).abs() > f64::EPSILON && !mutations.contains(&json_val) {
1047→  1047→                        mutations.push(json_val);
1048→  1048→                    }
1049→  1049→                }
1050→  1050→            }
1051→  1051→            mutations
1052→  1052→        }
