278→   278→// ---------------------------------------------------------------------------
279→   279→// MetaStrategy — adaptive selection over registered strategies
280→   280→// ---------------------------------------------------------------------------
281→   281→
282→   282→use rand::rngs::StdRng;
283→   283→use rand::{Rng, SeedableRng};
284→   284→use std::collections::VecDeque;
285→   285→
286→   286→/// Per-strategy scoring state.
287→   287→struct StrategyState {
288→   288→    /// The strategy implementation.
289→   289→    strategy: Box<dyn InputStrategy>,
290→   290→    /// Sliding window of recent outcomes (true = new path discovered).
291→   291→    window: VecDeque<bool>,
292→   292→    /// Total candidates supplied so far.
293→   293→    total_supplied: u64,
294→   294→    /// Whether the strategy has been exhausted (returned None from next()).
295→   295→    exhausted: bool,
296→   296→}
297→   297→
298→   298→/// Adaptive meta-strategy that selects among registered [`InputStrategy`]
299→   299→/// implementations using outcome-based scoring.
300→   300→///
301→   301→/// Selection algorithm:
302→   302→/// 1. **Static weights**: if configured, use weighted random sampling among
303→   303→///    non-exhausted strategies. On exhaustion, redistribute uniformly.
304→   304→/// 2. **Adaptive**: score = hit rate over sliding window. Cold-start strategies
305→   305→///    (fewer than threshold candidates) get the average score of graduated
306→   306→///    strategies. Floor prevents any strategy from dropping below a minimum
307→   307→///    allocation.
308→   308→/// 3. **Round-robin**: if adaptive is disabled and no static weights.
309→   309→pub struct MetaStrategy {
310→   310→    states: Vec<StrategyState>,
311→   311→    config: MetaConfig,
312→   312→    /// Round-robin index (used when adaptive=false and no static_weights).
313→   313→    rr_index: usize,
314→   314→}
315→   315→
316→   316→impl MetaStrategy {
317→   317→    pub fn new(strategies: Vec<Box<dyn InputStrategy>>, config: MetaConfig) -> Self {
318→   318→        let states = strategies
319→   319→            .into_iter()
320→   320→            .map(|s| StrategyState {
321→   321→                strategy: s,
322→   322→                window: VecDeque::with_capacity(config.window_size),
323→   323→                total_supplied: 0,
324→   324→                exhausted: false,
325→   325→            })
326→   326→            .collect();
327→   327→        Self {
328→   328→            states,
329→   329→            config,
330→   330→            rr_index: 0,
331→   331→        }
332→   332→    }
333→   333→
334→   334→    /// Select and invoke the next strategy, returning the candidate inputs
335→   335→    /// and the index of the strategy that produced them.
336→   336→    ///
337→   337→    /// Returns `None` when all strategies are exhausted.
338→   338→    pub fn next(&mut self, ctx: &StrategyContext, rng: &mut impl Rng) -> Option<(Vec<Value>, usize)> {
339→   339→        if self.all_exhausted() {
340→   340→            return None;
341→   341→        }
342→   342→
343→   343→        if self.config.static_weights.is_some() {
344→   344→            self.next_static(ctx, rng)
345→   345→        } else if self.config.adaptive {
346→   346→            self.next_adaptive(ctx, rng)
347→   347→        } else {
348→   348→            self.next_round_robin(ctx)
349→   349→        }
350→   350→    }
351→   351→
352→   352→    /// Fan out execution feedback to all registered strategies.
353→   353→    pub fn feedback(&mut self, inputs: &[Value], result: &ExecuteResult, was_new_path: bool) {
354→   354→        for state in &mut self.states {
355→   355→            if !state.exhausted {
356→   356→                state.strategy.feedback(inputs, result, was_new_path);
357→   357→            }
358→   358→        }
359→   359→    }
360→   360→
361→   361→    /// Record an outcome for a specific strategy (called after execution).
362→   362→    pub fn record_outcome(&mut self, strategy_idx: usize, was_new_path: bool) {
363→   363→        if let Some(state) = self.states.get_mut(strategy_idx) {
364→   364→            if state.window.len() >= self.config.window_size {
365→   365→                state.window.pop_front();
366→   366→            }
367→   367→            state.window.push_back(was_new_path);
368→   368→        }
369→   369→    }
370→   370→
371→   371→    /// The name of the strategy at the given index.
372→   372→    pub fn strategy_name(&self, idx: usize) -> &str {
373→   373→        self.states[idx].strategy.name()
374→   374→    }
375→   375→
376→   376→    /// Number of registered strategies.
377→   377→    pub fn len(&self) -> usize {
378→   378→        self.states.len()
379→   379→    }
380→   380→
381→   381→    /// Whether no strategies are registered.
382→   382→    pub fn is_empty(&self) -> bool {
383→   383→        self.states.is_empty()
384→   384→    }
385→   385→
386→   386→    fn all_exhausted(&self) -> bool {
387→   387→        self.states.iter().all(|s| s.exhausted)
388→   388→    }
389→   389→
390→   390→    /// Try to get the next candidate from a specific strategy, marking it
391→   391→    /// exhausted if it returns None.
392→   392→    fn try_next(&mut self, idx: usize, ctx: &StrategyContext) -> Option<Vec<Value>> {
393→   393→        let state = &mut self.states[idx];
394→   394→        if state.exhausted {
395→   395→            return None;
396→   396→        }
397→   397→        match state.strategy.next(ctx) {
398→   398→            Some(inputs) => {
399→   399→                state.total_supplied += 1;
400→   400→                Some(inputs)
401→   401→            }
402→   402→            None => {
403→   403→                state.exhausted = true;
404→   404→                None
405→   405→            }
406→   406→        }
407→   407→    }
408→   408→
409→   409→    // --- Selection modes ---
410→   410→
411→   411→    fn next_static(&mut self, ctx: &StrategyContext, rng: &mut impl Rng) -> Option<(Vec<Value>, usize)> {
412→   412→        let weights = self.config.static_weights.clone()?;
413→   413→
414→   414→        // Build weight vector for non-exhausted strategies.
415→   415→        loop {
416→   416→            let mut candidates: Vec<(usize, f64)> = Vec::new();
417→   417→            for (idx, state) in self.states.iter().enumerate() {
418→   418→                if state.exhausted {
419→   419→                    continue;
420→   420→                }
421→   421→                let weight = weights
422→   422→                    .iter()
423→   423→                    .find(|(name, _)| name == state.strategy.name())
424→   424→                    .map(|(_, w)| *w)
425→   425→                    .unwrap_or(1.0);
426→   426→                candidates.push((idx, weight));
427→   427→            }
428→   428→
429→   429→            if candidates.is_empty() {
430→   430→                return None;
431→   431→            }
432→   432→
433→   433→            let idx = weighted_select(&candidates, rng);
434→   434→            if let Some(inputs) = self.try_next(idx, ctx) {
435→   435→                return Some((inputs, idx));
436→   436→            }
437→   437→            // Strategy exhausted on this call; loop to rebuild candidates.
438→   438→        }
439→   439→    }
440→   440→
441→   441→    fn next_adaptive(&mut self, ctx: &StrategyContext, rng: &mut impl Rng) -> Option<(Vec<Value>, usize)> {
442→   442→        loop {
443→   443→            let scores = self.compute_scores();
444→   444→            let candidates: Vec<(usize, f64)> = scores
445→   445→                .into_iter()
446→   446→                .filter(|(idx, _)| !self.states[*idx].exhausted)
447→   447→                .collect();
448→   448→
449→   449→            if candidates.is_empty() {
450→   450→                return None;
451→   451→            }
452→   452→
453→   453→            let idx = weighted_select(&candidates, rng);
454→   454→            if let Some(inputs) = self.try_next(idx, ctx) {
455→   455→                return Some((inputs, idx));
456→   456→            }
457→   457→            // Strategy exhausted; loop to recompute.
458→   458→        }
459→   459→    }
460→   460→
461→   461→    fn next_round_robin(&mut self, ctx: &StrategyContext) -> Option<(Vec<Value>, usize)> {
462→   462→        let n = self.states.len();
463→   463→        for _ in 0..n {
464→   464→            let idx = self.rr_index % n;
465→   465→            self.rr_index = self.rr_index.wrapping_add(1);
466→   466→            if let Some(inputs) = self.try_next(idx, ctx) {
467→   467→                return Some((inputs, idx));
468→   468→            }
469→   469→        }
470→   470→        None
471→   471→    }
472→   472→
473→   473→    /// Compute adaptive scores for all non-exhausted strategies.
474→   474→    fn compute_scores(&self) -> Vec<(usize, f64)> {
475→   475→        // First pass: compute hit rates for graduated strategies to derive average.
476→   476→        let mut graduated_scores: Vec<f64> = Vec::new();
477→   477→        for (idx, state) in self.states.iter().enumerate() {
478→   478→            if state.exhausted {
479→   479→                continue;
480→   480→            }
481→   481→            let threshold = self.effective_cold_start(idx);
482→   482→            if state.total_supplied >= threshold {
483→   483→                graduated_scores.push(hit_rate(&state.window));
484→   484→            }
485→   485→        }
486→   486→        let avg_score = if graduated_scores.is_empty() {
487→   487→            1.0
488→   488→        } else {
489→   489→            graduated_scores.iter().sum::<f64>() / graduated_scores.len() as f64
490→   490→        };
491→   491→
492→   492→        // Second pass: assign scores.
493→   493→        let mut result = Vec::new();
494→   494→        for (idx, state) in self.states.iter().enumerate() {
495→   495→            if state.exhausted {
496→   496→                continue;
497→   497→            }
498→   498→            let threshold = self.effective_cold_start(idx);
499→   499→            let score = if state.total_supplied < threshold {
500→   500→                avg_score
501→   501→            } else {
502→   502→                hit_rate(&state.window)
503→   503→            };
504→   504→            result.push((idx, score.max(self.config.floor)));
505→   505→        }
506→   506→        result
507→   507→    }
508→   508→
509→   509→    /// Effective cold-start threshold for a strategy: min(configured, estimated_size).
510→   510→    fn effective_cold_start(&self, idx: usize) -> u64 {
511→   511→        let base = self.config.cold_start_threshold;
512→   512→        match self.states[idx].strategy.estimated_size() {
513→   513→            Some(size) => base.min(size),
514→   514→            None => base,
515→   515→        }
516→   516→    }
517→   517→}
518→   518→
519→   519→// ---------------------------------------------------------------------------
520→   520→// Helpers
521→   521→// ---------------------------------------------------------------------------
522→   522→
523→   523→/// Hit rate: fraction of `true` values in the window. Returns 0.0 for empty windows.
524→   524→fn hit_rate(window: &VecDeque<bool>) -> f64 {
525→   525→    if window.is_empty() {
526→   526→        return 0.0;
527→   527→    }
528→   528→    let hits = window.iter().filter(|&&b| b).count();
529→   529→    hits as f64 / window.len() as f64
530→   530→}
531→   531→
532→   532→/// Weighted random selection. Returns the index from `candidates`.
533→   533→/// Panics if `candidates` is empty.
534→   534→fn weighted_select(candidates: &[(usize, f64)], rng: &mut impl Rng) -> usize {
535→   535→    let total: f64 = candidates.iter().map(|(_, w)| w).sum();
536→   536→    if total <= 0.0 {
537→   537→        // All weights zero — fall back to uniform.
538→   538→        let pick = rng.random_range(0..candidates.len());
539→   539→        return candidates[pick].0;
540→   540→    }
541→   541→    let mut roll: f64 = rng.random_range(0.0..total);
542→   542→    for &(idx, weight) in candidates {
543→   543→        roll -= weight;
544→   544→        if roll <= 0.0 {
545→   545→            return idx;
546→   546→        }
547→   547→    }
548→   548→    // Floating-point rounding: return last candidate.
549→   549→    candidates.last().unwrap().0
550→   550→}
551→   551→
552→   552→// ---------------------------------------------------------------------------
553→   553→// PoolSeedsStrategy — yields cross-function pool seeds in order
554→   554→// ---------------------------------------------------------------------------
555→   555→
556→   556→/// Exhaustible strategy that yields pre-collected pool seed inputs from
557→   557→/// cross-function seed sharing (`.shatter/seeds/pool.json`).
558→   558→pub struct PoolSeedsStrategy {
559→   559→    seeds: Vec<Vec<Value>>,
560→   560→    index: usize,
561→   561→}
562→   562→
563→   563→impl PoolSeedsStrategy {
564→   564→    pub fn new(seeds: Vec<Vec<Value>>) -> Self {
565→   565→        Self { seeds, index: 0 }
566→   566→    }
567→   567→}
568→   568→
569→   569→impl InputStrategy for PoolSeedsStrategy {
570→   570→    fn next(&mut self, _ctx: &StrategyContext) -> Option<Vec<Value>> {
571→   571→        if self.index < self.seeds.len() {
572→   572→            let v = self.seeds[self.index].clone();
573→   573→            self.index += 1;
574→   574→            Some(v)
575→   575→        } else {
576→   576→            None
577→   577→        }
578→   578→    }
579→   579→
580→   580→    fn name(&self) -> &str {
581→   581→        "pool"
582→   582→    }
583→   583→
584→   584→    fn estimated_size(&self) -> Option<u64> {
585→   585→        Some(self.seeds.len() as u64)
586→   586→    }
587→   587→}
588→   588→
589→   589→// ---------------------------------------------------------------------------
590→   590→// FuzzerStrategy — infinite, feedback-driven mutation and crossover
591→   591→// ---------------------------------------------------------------------------
592→   592→
593→   593→/// Default per-parameter mutation probability for the fuzzer strategy.
594→   594→const FUZZER_MUTATION_RATE: f64 = 0.3;
595→   595→
596→   596→/// Default crossover probability when two parents are available.
597→   597→const FUZZER_CROSSOVER_RATE: f64 = 0.7;
598→   598→
599→   599→/// Infinite strategy that mutates and crosses over inputs which hit Unknown
600→   600→/// constraints or discovered new paths.
601→   601→///
602→   602→/// Feedback records interesting inputs (those reaching branches with no
603→   603→/// symbolic constraint, or discovering new coverage). `next()` draws from
604→   604→/// the interesting pool, generating mutations via `fuzz_inputs()`,
605→   605→/// `mutate_inputs()`, and `crossover_inputs()`.
606→   606→pub struct FuzzerStrategy {
607→   607→    rng: StdRng,
608→   608→    /// Inputs that hit Unknown constraints or new paths — seeds for mutation.
609→   609→    interesting: Vec<Vec<Value>>,
610→   610→    /// Pending mutations generated from a feedback round, drained by `next()`.
611→   611→    pending: VecDeque<Vec<Value>>,
612→   612→}
613→   613→
614→   614→impl FuzzerStrategy {
615→   615→    pub fn new(seed: Option<u64>) -> Self {
616→   616→        let rng = match seed {
617→   617→            Some(s) => StdRng::seed_from_u64(s),
618→   618→            None => StdRng::from_os_rng(),
619→   619→        };
620→   620→        Self {
621→   621→            rng,
622→   622→            interesting: Vec::new(),
623→   623→            pending: VecDeque::new(),
624→   624→        }
625→   625→    }
626→   626→
627→   627→    /// Refill `self.pending` by mutating a random interesting input.
628→   628→    fn refill(&mut self, ctx: &StrategyContext) {
629→   629→        if self.interesting.is_empty() {
630→   630→            return;
631→   631→        }
632→   632→
633→   633→        let idx = self.rng.random_range(0..self.interesting.len());
634→   634→        let base = self.interesting[idx].clone();
635→   635→
636→   636→        // 1. Simple value-level mutations (from orchestrator's fuzz_inputs).
637→   637→        for mutated in fuzz_inputs(&base) {
638→   638→            self.pending.push_back(mutated);
639→   639→        }
640→   640→
641→   641→        // 2. Type-aware mutation via input_gen.
642→   642→        let params: Vec<ParamInfo> = ctx.params.clone();
643→   643→        let mutated = mutate_inputs(&base, &params, FUZZER_MUTATION_RATE, &[], &mut self.rng);
644→   644→        self.pending.push_back(mutated);
645→   645→
646→   646→        // 3. Crossover when at least two interesting inputs exist.
647→   647→        if self.interesting.len() >= 2 {
648→   648→            let other_idx = loop {
649→   649→                let candidate = self.rng.random_range(0..self.interesting.len());
650→   650→                if candidate != idx || self.interesting.len() == 1 {
651→   651→                    break candidate;
652→   652→                }
653→   653→            };
654→   654→            let (child_a, _child_b) = crossover_inputs(
655→   655→                &base,
656→   656→                &self.interesting[other_idx],
657→   657→                &params,
658→   658→                FUZZER_CROSSOVER_RATE,
659→   659→                &mut self.rng,
660→   660→            );
661→   661→            self.pending.push_back(child_a);
662→   662→        }
663→   663→    }
664→   664→}
665→   665→
666→   666→impl InputStrategy for FuzzerStrategy {
667→   667→    fn next(&mut self, ctx: &StrategyContext) -> Option<Vec<Value>> {
668→   668→        if let Some(candidate) = self.pending.pop_front() {
669→   669→            return Some(candidate);
670→   670→        }
671→   671→
672→   672→        // Try to refill from interesting pool.
673→   673→        self.refill(ctx);
674→   674→        self.pending.pop_front()
675→   675→    }
676→   676→
677→   677→    fn feedback(&mut self, inputs: &[Value], result: &ExecuteResult, was_new_path: bool) {
678→   678→        // Record inputs that discovered new coverage.
679→   679→        if was_new_path {
680→   680→            self.interesting.push(inputs.to_vec());
681→   681→            return;
682→   682→        }
683→   683→
684→   684→        // Record inputs that hit Unknown constraints (branches the solver
685→   685→        // cannot handle, so fuzzing is the only way to explore them).
686→   686→        let has_unknown = result.branch_path.iter().any(|decision| {
687→   687→            matches!(decision.constraint, SymConstraint::Unknown { .. })
688→   688→        });
689→   689→        if has_unknown {
690→   690→            self.interesting.push(inputs.to_vec());
691→   691→        }
692→   692→    }
693→   693→
694→   694→    fn name(&self) -> &str {
695→   695→        "fuzzer"
696→   696→    }
697→   697→}
698→   698→
699→   699→// ---------------------------------------------------------------------------
700→   700→// Z3SolverStrategy — infinite, feedback-driven constraint solving
701→   701→// ---------------------------------------------------------------------------
702→   702→
703→   703→/// Strategy name constant for Z3 solver, used for discovery attribution.
704→   704→const Z3_SOLVER_STRATEGY_NAME: &str = "z3_solver";
705→   705→
706→   706→/// Reactive strategy that uses Z3 constraint solving to generate inputs
707→   707→/// targeting unexplored branches.
708→   708→///
709→   709→/// `feedback()` extracts symbolic constraints from execution results, negates
710→   710→/// each solvable constraint, solves with Z3, and overlays solutions onto the
711→   711→/// base inputs. Solved inputs queue in `pending` and drain via `next()`.
712→   712→///
713→   713→/// Infinite: produces work while unsolved constraints exist, but the queue
714→   714→/// may be empty between feedback cycles.
715→   715→pub struct Z3SolverStrategy {
716→   716→    solver_timeout_ms: Option<u64>,
717→   717→    param_infos: Vec<ParamInfo>,
718→   718→    pending: VecDeque<Vec<Value>>,
719→   719→}
720→   720→
721→   721→impl Z3SolverStrategy {
722→   722→    pub fn new(solver_timeout_ms: Option<u64>, param_infos: Vec<ParamInfo>) -> Self {
723→   723→        Self {
724→   724→            solver_timeout_ms,
725→   725→            param_infos,
726→   726→            pending: VecDeque::new(),
727→   727→        }
728→   728→    }
729→   729→}
730→   730→
731→   731→impl InputStrategy for Z3SolverStrategy {
732→   732→    fn next(&mut self, _ctx: &StrategyContext) -> Option<Vec<Value>> {
733→   733→        self.pending.pop_front()
734→   734→    }
735→   735→
736→   736→    fn feedback(&mut self, inputs: &[Value], result: &ExecuteResult, _was_new_path: bool) {
737→   737→        let sym_constraints = crate::orchestrator::extract_sym_constraints(result);
738→   738→
739→   739→        let solvable: Vec<SymExpr> = sym_constraints
740→   740→            .iter()
741→   741→            .filter_map(|c| c.clone())
742→   742→            .collect();
743→   743→
744→   744→        if solvable.is_empty() {
745→   745→            return;
746→   746→        }
747→   747→
748→   748→        let param_names: Vec<String> = self.param_infos.iter().map(|p| p.name.clone()).collect();
749→   749→
750→   750→        for solve_idx in 0..solvable.len() {
751→   751→            // solve_for_new_path may fail (unsupported expressions, type mismatches,
752→   752→            // or constraint/param misalignment). Treat all failures as "no solution".
753→   753→            let solve_result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
754→   754→                solver::solve_for_new_path(
755→   755→                    &solvable,
756→   756→                    solve_idx,
757→   757→                    self.solver_timeout_ms,
758→   758→                    &self.param_infos,
759→   759→                )
760→   760→            }));
761→   761→
762→   762→            match solve_result {
763→   763→                Ok(Ok(SolveResult::Sat(values))) => {
764→   764→                    let new_inputs = crate::orchestrator::overlay_solved_values(
765→   765→                        inputs,
766→   766→                        &values,
767→   767→                        &param_names,
768→   768→                    );
769→   769→                    self.pending.push_back(new_inputs);
770→   770→                }
771→   771→                _ => {
772→   772→                    // Unsat, solver error, or panic (debug_assert on param mismatch).
773→   773→                    // Stall tracking is the orchestrator's responsibility.
774→   774→                }
775→   775→            }
776→   776→        }
777→   777→    }
778→   778→
779→   779→    fn name(&self) -> &str {
780→   780→        Z3_SOLVER_STRATEGY_NAME
781→   781→    }
782→   782→}
783→   783→
784→   784→// ---------------------------------------------------------------------------
785→   785→// Tests
786→   786→// ---------------------------------------------------------------------------
787→   787→
788→   788→#[cfg(test)]
789→   789→mod tests {
790→   790→    use super::*;
791→   791→    use crate::types::TypeInfo;
792→   792→    use rand::rngs::StdRng;
793→   793→    use rand::SeedableRng;
794→   794→
795→   795→    /// Minimal strategy that yields a fixed sequence of inputs.
796→   796→    struct FixedStrategy {
797→   797→        name: &'static str,
798→   798→        items: Vec<Vec<Value>>,
799→   799→        idx: usize,
800→   800→    }

